module top_module( inverted_i, o);input      [1:0] inverted_i;
   output reg [1:0] o;


   always @* begin
     if      (inverted_i==2'b00) o = 2'b11;
     else if (inverted_i==2'b01) o = 2'b10;
     else if (inverted_i==2'b10) o = 2'b01;
     else if (inverted_i==2'b11) o = 2'b00;
     else               o = 2'b00; 
   end

endmodule
